@before(PreProcessRequest(maxdev))
class devicestate:
    # The devicestate class exposes internal diagnostic or operational information
    # about the filter wheel (e.g. position, moving state, errors) as a list of key/value pairs.
    # It allows client software to monitor the device’s current status beyond standard properties.
    def on_get(self, req: Request, resp: Response, devnum: int):
        if not fw.isConnected() : ##IS DEV CONNECTED##: # TODO modifié ici
            resp.text = PropertyResponse(None, req,
                            NotConnectedException()).json
            return
        try:
            # ----------------------
            val = []
            # val.append(StateValue('## NAME ##', ## GET VAL ##))
            # TODO modifié ici
            val.append(StateValue('Position', fw.currentPosition))
            val.append(StateValue('Angle', fw.currentAngle))
            val.append(StateValue('Moving', fw.isMoving()))
            val.append(StateValue('Error', fw.lastError))
            # ----------------------
            resp.text = PropertyResponse(val, req).json
        except Exception as ex:
            resp.text = PropertyResponse(None, req,
                            DriverException(0x500, 'filterwheel.Devicestate failed', ex)).json


