@before(PreProcessRequest(maxdev))
class position:

    def on_get(self, req: Request, resp: Response, devnum: int):
        if not fw.isConnected() : ##IS DEV CONNECTED##: #TODO modifié ici
            resp.text = PropertyResponse(None, req,
                            NotConnectedException()).json
            return
        
        try:
            # ----------------------
            ## GET PROPERTY ## #TODO modifié ici
            # ----------------------
            val = fw.get_position()
            resp.text = PropertyResponse(val, req).json
        except Exception as ex:
            resp.text = PropertyResponse(None, req,
                            DriverException(0x500, 'Filterwheel.Position failed', ex)).json

    def on_put(self, req: Request, resp: Response, devnum: int):
        if not fw.isConnected() : ## IS DEV CONNECTED ##:#TODO modifié ici
            resp.text = PropertyResponse(None, req,
                            NotConnectedException()).json
            return
        
        positionstr = get_request_field('Position', req)      # Raises 400 bad request if missing
        try:
            position = int(positionstr)
        except:
            resp.text = MethodResponse(req,
                            InvalidValueException(f'Position {positionstr} not a valid integer.')).json
            return
        ### RANGE CHECK AS NEEDED ###  # Raise Alpaca InvalidValueException with details! # TODO ajouté ici
        if position < 0 or position >= len(fw.filter_names):
            resp.text = MethodResponse(req,
                            InvalidValueException(f'Position {position} out of range.')).json
            return
        try:
            # -----------------------------
            ### DEVICE OPERATION(PARAM) ###
            # -----------------------------
            fw.set_position(position) 
            resp.text = MethodResponse(req).json
        except Exception as ex:
            resp.text = MethodResponse(req,
                            DriverException(0x500, 'Filterwheel.Position failed', ex)).json

